import React from 'react'
import { Container } from 'react-bootstrap'
import './App.css';

function App() {
  return (
   <>
   <Heather>
    <main className="py-3">
      <Container>
        <h1>Dobrodošli na sajt za prodaju venčanica</h1>
      </Container>
    </main>
   </Heather>
   </>
  );
}

export default App;
